// config for v3
formatter: function({dictionary, file}) {
  return dictionary.allProperties
    .map(token => `--${token.name}: ${token.value};`)
    .join('\n');
}

// BROKEN in v3
format: ({dictionary, options}) => {
  return dictionary.allProperties.map(...);
}

/* dist/css/variables.css — generated, do not edit */
:root {
  /* Primitives */
  --color-gray-50: #f9fafb;
  --color-gray-900: #111827;
  --color-blue-600: #2563eb;
  --color-blue-700: #1d4ed8;

  /* Semantic — light theme */
  --color-bg-primary: #ffffff;
  --color-text-primary: #111827;
  --color-action-primary: #2563eb;
  --color-status-error: #dc2626;
  --spacing-4: 1rem;
  --radius-md: 0.375rem;
}

[data-theme="dark"] {
  /* Semantic — dark theme */
  --color-bg-primary: #111827;
  --color-text-primary: #f9fafb;
  --color-action-primary: #3b82f6;
  --color-status-error: #fca5a5;
}

// tailwind.config.js — reads from generated JS tokens
const tokens = require('./dist/js/tokens');

function flattenTokens(obj, prefix = '') {
  return Object.entries(obj).reduce((acc, [key, value]) => {
    const newKey = prefix ? `${prefix}-${key}` : key;
    if (typeof value === 'object' && value !== null && !value.value) {
      return { ...acc, ...flattenTokens(value, newKey) };
    }
    return { ...acc, [newKey]: value.value ?? value };
  }, {});
}

module.exports = {
  theme: {
    colors: flattenTokens(tokens.color),
    spacing: flattenTokens(tokens.spacing),
    borderRadius: flattenTokens(tokens.borderRadius),
  },
};

// build-tokens.mjs
import StyleDictionary from 'style-dictionary';

const config = {
  source: ['tokens/**/*.json'],
  platforms: {
    css: {
      transformGroup: 'css',
      buildPath: 'dist/css/',
      files: [
        {
          destination: 'variables.css',
          format: 'css/variables',
        },
      ],
    },
    js: {
      transformGroup: 'js',
      buildPath: 'dist/js/',
      files: [
        {
          destination: 'tokens.js',
          format: 'javascript/es6',
        },
      ],
    },
  },
};

const sd = new StyleDictionary.default(config);
sd.buildAllPlatforms();
console.log('Tokens built successfully');
